# ============================================================================
# API Configuration - 从环境变量或 .flocks/.secret.json 读取
# ============================================================================
def _load_secret_config():
    """从 .flocks/.secret.json 加载密钥配置（如果存在）"""
    secret_path = Path(__file__).parent.parent / ".flocks" / ".secret.json"
    if secret_path.exists():
        try:
            with open(secret_path) as f:
                return json.load(f)
        except (json.JSONDecodeError, OSError):
            pass
    return {}

_secrets = _load_secret_config()

ANTHROPIC_API_KEY = os.environ.get("ANTHROPIC_API_KEY", _secrets.get("anthropic_api_key", ""))
ANTHROPIC_BASE_URL = os.environ.get("ANTHROPIC_BASE_URL", _secrets.get("anthropic_base_url", "https://api.anthropic.com"))
GLM_API_KEY = os.environ.get("GLM_API_KEY", _secrets.get("glm_api_key", ""))
GLM_BASE_URL = os.environ.get("GLM_BASE_URL", _secrets.get("glm_base_url", ""))

