@pytest.mark.requires_anthropic_key
def test_anthropic():
    """测试 Anthropic Claude Sonnet 4"""
    print("\n" + "="*100)
    print("🧪 TEST 1: Anthropic Claude Sonnet 4")
    print("="*100)

    if not ANTHROPIC_API_KEY:
        pytest.skip("ANTHROPIC_API_KEY not set (env var or .flocks/.secret.json)")

    try:
        from anthropic import Anthropic
        
        client = Anthropic(
            api_key=ANTHROPIC_API_KEY,
            base_url=ANTHROPIC_BASE_URL,
        )
        
        # 只使用前 2 条消息（system + user query），不包含工具调用历史
        clean_messages = MESSAGES[:2]
        
        # 转换为 Anthropic 格式
        anthropic_messages = []
        system_message = None
        for msg in clean_messages:
            if msg["role"] == "system":
                system_message = msg["content"]
            else:
                anthropic_messages.append({
                    "role": msg["role"],
                    "content": msg["content"]
                })
        
        # 转换工具格式
        anthropic_tools = []
        for tool in TOOLS:
            func = tool["function"]
            anthropic_tools.append({
                "name": func["name"],
                "description": func["description"],
                "input_schema": func["parameters"]
            })
        
        print(f"\n📤 Calling Anthropic API...")
        print(f"   Model: claude-sonnet-4-20250514")
        print(f"   System message length: {len(system_message) if system_message else 0} chars")
        print(f"   Messages: {len(anthropic_messages)}")
        print(f"   Tools: {len(anthropic_tools)}")
        
        response = client.messages.create(
            model="claude-sonnet-4-20250514",
            max_tokens=4096,
            system=system_message if system_message else None,
            messages=anthropic_messages,
            tools=anthropic_tools,
        )
        
        print(f"\n📥 Response:")
        print(f"   Stop reason: {response.stop_reason}")
        print(f"   Content blocks: {len(response.content)}")
        
        has_tool_use = False
        for i, block in enumerate(response.content):
            if block.type == "text":
                text_preview = block.text[:200] if block.text else ""
                print(f"\n   [{i+1}] Text: {text_preview}")
            elif block.type == "tool_use":
                has_tool_use = True
                print(f"\n   ✅ [{i+1}] Tool Use:")
                print(f"       ID: {block.id}")
                print(f"       Name: {block.name}")
                print(f"       Input: {json.dumps(block.input, ensure_ascii=False)}")
        
        if not has_tool_use:
            print(f"\n   ❌ No tool calls in response")
        
        return has_tool_use
        
    except Exception as e:
        print(f"\n❌ Error: {e}")
        import traceback
        traceback.print_exc()
        return False


@pytest.mark.requires_glm_key
def test_glm():
    """测试 GLM-4-7-251222 (OpenAI-compatible)"""
    print("\n" + "="*100)
    print("🧪 TEST 2: GLM-4-7-251222 (OpenAI-compatible)")
    print("="*100)

    if not GLM_API_KEY or not GLM_BASE_URL:
        pytest.skip("GLM_API_KEY/GLM_BASE_URL not set (env var or .flocks/.secret.json)")

    try:
        from openai import OpenAI
        
        client = OpenAI(
            api_key=GLM_API_KEY,
            base_url=GLM_BASE_URL,
        )
        
        # 只使用前 2 条消息（system + user query），不包含工具调用历史
        clean_messages = MESSAGES[:2]
        
        print(f"\n📤 Calling GLM API...")
        print(f"   Model: volcengine: glm-4-7-251222")
        print(f"   Messages: {len(clean_messages)} (clean, no history)")
        print(f"   Tools: {len(TOOLS)}")
        
        response = client.chat.completions.create(
            model="volcengine: glm-4-7-251222",
            messages=clean_messages,
            tools=TOOLS,
            max_tokens=4096,
        )
        
        print(f"\n📥 Response:")
        print(f"   Finish reason: {response.choices[0].finish_reason}")
        message = response.choices[0].message
        
        if message.content:
            print(f"\n   Text: {message.content[:200]}")
        
        if message.tool_calls:
            print(f"\n   ✅ Tool Calls: {len(message.tool_calls)}")
            for i, tc in enumerate(message.tool_calls):
                print(f"\n   [{i+1}] Tool Call:")
                print(f"       ID: {tc.id}")
                print(f"       Name: {tc.function.name}")
                print(f"       Arguments: {tc.function.arguments}")
            return True
        else:
            print(f"\n   ❌ No tool calls in response")
            return False
        
    except Exception as e:
        print(f"\n❌ Error: {e}")
        import traceback
        traceback.print_exc()
        return False


